import React, { useState } from 'react';
import { View, Button, Text, TextInput } from 'react-native';

const App = () => {
  const [code, setCode] = useState('');
  const [token, setToken] = useState('');

  const handleLogin = async () => {
    try {
      const response = await fetch('https://your-auth-server.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${code}&client_id=mobile_app_client_123&client_secret=secret_abc123xyz456`,
      });

      if (!response.ok) {
        throw new Error('Failed to authenticate');
      }

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      console.error('Error:', error);
    }
  };

  return (
    <View style={{ padding: 20 }}>
      <TextInput
        placeholder="Authorization Code"
        value={code}
        onChangeText={setCode}
        style={{ height: 40, borderColor: 'gray', borderWidth: 1, marginBottom: 10 }}
      />
      <Button title="Login" onPress={handleLogin} />
      {token && (
        <Text style={{ marginTop: 20 }}>Access Token: {token}</Text>
      )}
    </View>
  );
};

export default App;